import React from 'react';
import './About.css';
import { FadeTransition } from './PageTransition';

const About = () => {
  const skills = [
    { category: 'Frontend', items: ['React', 'JavaScript', 'HTML5', 'Angular', 'CSS3'] },
    { category: 'Backend', items: ['Node.js', 'ExpressJS', 'SQL', 'PHP', 'MongoDB'] },
    { category: 'Tools', items: ['Git', 'Docker', 'AWS', 'VS Code', 'DevOps'] },
    { category: 'Programming', items: ['Python', 'Java', 'C++', 'C', 'R'] },
    { category: 'Operating Systems', items: ['Windows', 'Linux', 'Ubuntu', 'Mac'] },
    { category: 'Other', items: ['REST APIs', 'Agile', 'UI/UX', 'Testing'] }
  ];

  return (
    <FadeTransition>
      <section className="about section">
        <div className="container">
          <h2 className="section-title">About Me</h2>
          <div className="about-content">
            <div className="about-text">
              <p>
                As a Computer Science graduate student at the University of Missouri-Columbia, I combine my expertise 
                in Cybersecurity, AI/ML, and Full Stack Development to create innovative solutions. My academic 
                foundation, coupled with hands-on experience, enables me to bridge the gap between theoretical 
                concepts and real-world applications in today's dynamic tech landscape.
              </p>
              <p>
                My diverse background encompasses critical roles in both security and development - from implementing 
                advanced machine learning models as a Research Assistant to conducting comprehensive security 
                assessments as a Cybersecurity Analyst. This multifaceted experience has shaped my approach to 
                problem-solving, where I seamlessly integrate security considerations with cutting-edge technological 
                solutions.
              </p>
              <p>
                In my current research, I focus on exploring the synergies between machine learning and cybersecurity. 
                My contributions to facial recognition technology and IoT systems, published in international journals, 
                reflect my dedication to advancing technological boundaries while maintaining robust security standards.
              </p>
            </div>
            <div className="skills-grid">
              {skills.map((skillGroup, index) => (
                <div key={index} className="skill-category">
                  <h3 className="skill-category-title">{skillGroup.category}</h3>
                  <ul className="skill-list">
                    {skillGroup.items.map((skill, skillIndex) => (
                      <li key={skillIndex} className="skill-item">
                        {skill}
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>
    </FadeTransition>
  );
};

export default About;
